INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Subtitles: Spanish Bonus', '(?i)^(?=.*(?:subs?|subtitles?|srt|vtt|subbed))(?=.*(?:(?:\bspa(?:nish)?\b|\besp(?:anol|a\u00f1ol)?\b|\bespanol\b|\bespa\u00f1ol\b|\bcastellano\b|\bcastilian\b)|(?:\blatino\b|\blatina\b|\blatam\b|\blatin[ ._-]?america(?:n)?\b|\blatinoamerica(?:no)?\b|\blatinoam[e\u00e9]rica(?:no)?\b|\bespa[n\u00f1]ol[ ._-]?latino\b|\blat(?:ino)?[ ._-]?dub(?:bed)?\b|\baudio[ ._-]?(?:latino|latam|spanish|espa[n\u00f1]ol)\b|\bcast(?:ellano)?\b|\bmex(?:ican|ico)?\b|\bmx\b|\bes[ ._-]?(?:la|lat|419|mx|es|us)\b|\bspa[ ._-]?(?:lat|la|mx|cast|es|419)\b|\besp[ ._-]?(?:lat|la|mx|cast|es|419)\b|[._ \-\[\(](?:es|spa|esp|lat|la|mx|es419)[._ \-\]\)]))).*$', 'Subtitle bonus for Spanish or Latino subtitle indicators. Helps prefer releases that are easier to use for Spanish viewers.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Subtitles: Spanish Bonus', 'Subtitles');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Subtitles: Spanish Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Subtitles: Block Hardcoded-Burned-In', '(?i)\b(?:hardcoded|hardsub(?:bed)?|burn(?:ed)?[ ._-]?in|burnt[ ._-]?in)\b', 'Heavy negative score for hardcoded, hardsubbed, burned-in, or burnt-in subtitle tags. Avoids releases where subtitles cannot be disabled.');
